const item = $input.first().json;

// ---- Tone instructions ----
const tones = {
  direct:         "Direct: action-first. Short sentences. No filler, no hedging. What to do, what to avoid, why it matters.",
  structured:     "Structured: playbook format. Ordered sections, numbered steps, repeatable frameworks.",
  conversational: "Conversational: natural, confident, plain language, second-person address.",
  concise:        "Concise: executive style. Minimal narrative. Decisions and outcomes only.",
  explanatory:    "Explanatory: teach-first. Clear explanation, then a concrete worked example.",
  persuasive:     "Persuasive: argument-driven. Make a claim, justify it, lead the reader to a conclusion.",
  editorial:      "Editorial: polished longform. Smooth transitions, strong narrative flow.",
  custom:         "Custom: follow the user's described style exactly, respecting all structural rules."
};

// ---- Opener instructions ----
// FIX: keys must match normalize(<form dropdown option>) exactly.
// Previously "Pain Promise" -> "pain_promise" missed the key
// "direct_pain_promise", and "Story" had no key at all, so every
// Story request silently rendered as a Pain Promise opener.
const openers = {
  pain_promise:  "Pain -> promise: name the reader's blockage, then promise the outcome. 'If you're stuck at X, this shows Y.'",
  myth_bust:     "Myth bust: state what most people believe (X), then reframe with the real lever (Y).",
  diagnostic:    "Diagnostic: open with questions that let the reader locate their own situation, then give the matching play.",
  example_first: "Example-first: open with a finished output, then reverse-engineer how to produce it.",
  story:         "Story: open with a short, specific anecdote (2-4 sentences) that dramatises the core problem. No fabricated people or events.",
  outcome_led:   "Outcome-led: state exactly what the reader will hold at the end: checklists, templates, targets."
};

function normalize(v) {
  return (v || "").toLowerCase().trim().replace(/\s+/g, "_");
}

const toneKey   = normalize(item["Tone"]);
const openerKey = normalize(item["Opener Type"]);

// FIX: form field is "Additional Notes" and must exist on the form,
// otherwise the custom-tone branch is unreachable dead code.
const notes = item["Additional Notes"] || "";

let resolvedTone = tones[toneKey] || tones.direct;
if (toneKey === "custom" && notes.trim() !== "") {
  resolvedTone = notes;
}

const resolvedOpener = openers[openerKey] || openers.pain_promise;

// FIX: fail loudly instead of silently degrading.
if (!openers[openerKey]) {
  console.warn(`Unmapped opener "${item["Opener Type"]}" -> "${openerKey}". Falling back to pain_promise.`);
}
if (!tones[toneKey]) {
  console.warn(`Unmapped tone "${item["Tone"]}" -> "${toneKey}". Falling back to direct.`);
}

item.instructions = {
  writing_style: resolvedTone,
  opener: resolvedOpener
};

return $input.all();

// Drive only converts to a Google Doc if the upload is text/html.
// convertToFile emits text/plain, so it is corrected here.
const item = $input.item;
if (item.binary && item.binary.file) {
  item.binary.file.mimeType = 'text/html';
}
return item;
